//
//  WaveTables.swift
//  brWave
//
//  Factory wavetable data used by the Behringer Wave editor.
//  Each wavetable contains 64 complete single-cycle waves at 128 samples each.
//  These arrays are already expanded to full 128-sample cycles.
//

import Foundation

