    static func displayName(for index: Int) -> String {
        guard names.indices.contains(index) else { return "WT \(index)" }
        return names[index]
    }

    static func slotDisplayName(for slot: Int) -> String {
        if let name = slotNames[slot] { return name }
        if slot <= 30 { return "Factory WT \(slot)" }
        if slot <= 63 { return "TR \(slot)" }
        return "User WT \(slot)"
    }

    static func localTableIndex(forSlot slot: Int) -> Int? {
        guard waveTables.indices.contains(slot) else { return nil }
        return slot
    }

    static func cycleSamples(tableIndex: Int, cycleIndex: Int) -> [Int8] {
        guard waveTables.indices.contains(tableIndex) else { return [] }
        let table = waveTables[tableIndex]
        guard !table.isEmpty else { return [] }
        let safeCycleIndex = min(max(0, cycleIndex), table.count - 1)
        return table[safeCycleIndex]
    }

    static func displayCycleSamples(tableIndex: Int, cycleIndex: Int) -> [Int8] {
        cycleSamples(tableIndex: tableIndex, cycleIndex: cycleIndex)
    }

    static func cycleIndex(forParameterValue value: Int, in tableIndex: Int) -> Int {
        guard waveTables.indices.contains(tableIndex) else { return 0 }
        let cycleCount = waveTables[tableIndex].count
        guard cycleCount > 0 else { return 0 }
        let clamped = min(max(0, value), 127)
        return Int((Double(clamped) / 127.0 * Double(cycleCount - 1)).rounded())
    }

